1	export const AudioPlayer = {
2		mounted() {
3			this.audio = document.getElementById("audio-element");
4			this.playPauseBtn = document.getElementById("play-pause-btn");
5			this.timeDisplay = document.getElementById("time-display");
6			this.textContainer = document.getElementById("chapter-text");
7			this.resyncBtn = document.getElementById("resync-btn");
8			this.timings = [];
9			this.currentWordIndex = -1;
10			this.autoScrollPaused = false;
11			this.isAutoScrolling = false;
12	
13			// Load persisted state
14			const collapsed =
15				localStorage.getItem("readaloud-player-collapsed") === "true";
16			if (collapsed) this.el.classList.add("collapsed");
17	
18			const savedSpeed = parseFloat(
19				localStorage.getItem("readaloud-playback-speed") || "1",
20			);
21			this.audio.playbackRate = savedSpeed;
22	
23			const savedVolume = parseFloat(
24				localStorage.getItem("readaloud-volume") || "1",
25			);
26			this.audio.volume = savedVolume;
27	
28			// Update volume slider UI
29			const volSlider = this.el.querySelector("[data-volume-slider]");
30			if (volSlider) volSlider.value = savedVolume;
31	
32			// Update speed button active state
33			this.updateSpeedButtons(savedSpeed);
34	
35			// Load audio
36			this.audio.src = this.el.dataset.audioUrl;
37	
38			// Load word-level timings
39			fetch(this.el.dataset.timingsUrl)
40				.then((r) => r.json())
41				.then((data) => {
42					this.timings = data.timings || [];
43					// Set up click-to-seek on word spans
44					this.setupWordClickListeners();
45				});
46	
47			// Restore position
48			const initialMs = parseInt(this.el.dataset.initialPosition || "0", 10);
49			if (initialMs > 0) {
50				this.audio.addEventListener(
51					"loadedmetadata",
52					() => {
53						this.audio.currentTime = initialMs / 1000;
54					},
55					{ once: true },
56				);
57			}
58	
59			// Play/pause button
60			this.playPauseBtn.addEventListener("click", () => this.togglePlayback());
61	
62			// Skip back/forward buttons
63			const skipBack = this.el.querySelector("[data-skip-back]");
64			const skipFwd = this.el.querySelector("[data-skip-forward]");
65			if (skipBack)
66				skipBack.addEventListener("click", () => {
67					this.audio.currentTime = Math.max(0, this.audio.currentTime - 10);
68				});
69			if (skipFwd)
70				skipFwd.addEventListener("click", () => {
71					this.audio.currentTime = Math.min(
72						this.audio.duration || Infinity,
73						this.audio.currentTime + 10,
74					);
75				});
76	
77			// Collapse toggle
78			const collapseToggle = this.el.querySelector("[data-collapse-toggle]");
79			if (collapseToggle) {
80				collapseToggle.addEventListener("click", () => {
81					const isCollapsed = this.el.classList.toggle("collapsed");
82					localStorage.setItem("readaloud-player-collapsed", isCollapsed);
83				});
84			}
85	
86			// Speed buttons
87			this.el.querySelectorAll("[data-speed]").forEach((btn) => {
88				btn.addEventListener("click", () => {
89					const speed = parseFloat(btn.dataset.speed);
90					this.setSpeed(speed);
91				});
92			});
93	
94			// Volume slider
95			if (volSlider) {
96				volSlider.addEventListener("input", () => {
97					const vol = parseFloat(volSlider.value);
98					this.audio.volume = vol;
99					localStorage.setItem("readaloud-volume", vol);
100				});
101			}
102	
103			// Scrubber: main + mini (store window listeners for cleanup)
104			this._scrubberCleanups = [];
105			const scrubber = this.el.querySelector("[data-scrubber]");
106			if (scrubber) {
107				this.setupScrubber(scrubber);
108			}
109	
110			const scrubberMini = this.el.querySelector("[data-scrubber-mini]");
111			if (scrubberMini) {
112				this.setupScrubber(scrubberMini);
113			}
114	
115			// Fallback: old progress-bar ID if present
116			const progressBar = document.getElementById("progress-bar");
117			if (progressBar && !scrubber && !scrubberMini) {
118				progressBar.addEventListener("click", (e) => {
119					const rect = progressBar.getBoundingClientRect();
120					const pct = (e.clientX - rect.left) / rect.width;
121					this.audio.currentTime = pct * this.audio.duration;
122				});
123			}
124	
125			// Time update: progress + time display + position reporting (low frequency)
126			this.audio.addEventListener("timeupdate", () => {
127				if (this.audio.duration) {
128					const pct = (this.audio.currentTime / this.audio.duration) * 100;
129	
130					// Update scrubber fills (main + mini)
131					const fill =
132						this.el.querySelector("[data-progress-fill]") ||
133						document.getElementById("progress-fill");
134					if (fill) fill.style.width = `${pct}%`;
135					const fillMini = this.el.querySelector("[data-progress-fill-mini]");
136					if (fillMini) fillMini.style.width = `${pct}%`;
137	
138					if (this.timeDisplay) {
139						this.timeDisplay.textContent =
140							this.formatTime(this.audio.currentTime) +
141							" / " +
142							this.formatTime(this.audio.duration);
143					}
144	
145					// Report position (throttled: every ~5s of audio time)
146					const nowMs = Math.round(this.audio.currentTime * 1000);
147					if (
148						!this._lastReportedMs ||
149						Math.abs(nowMs - this._lastReportedMs) >= 5000
150					) {
151						this._lastReportedMs = nowMs;
152						this.pushEvent("audio_position", { position_ms: nowMs });
153					}
154				}
155			});
156	
157			// High-frequency word highlighting via requestAnimationFrame (60fps)
158			this._rafId = null;
159			this._startHighlightLoop = () => {
160				const tick = () => {
161					if (this.audio && !this.audio.paused) {
162						this.highlightWord(this.audio.currentTime * 1000);
163						this._rafId = requestAnimationFrame(tick);
164					}
165				};
166				this._rafId = requestAnimationFrame(tick);
167			};
168			this._stopHighlightLoop = () => {
169				if (this._rafId) {
170					cancelAnimationFrame(this._rafId);
171					this._rafId = null;
172				}
173			};
174			this.audio.addEventListener("play", this._startHighlightLoop);
175			this.audio.addEventListener("pause", this._stopHighlightLoop);
176			this.audio.addEventListener("ended", this._stopHighlightLoop);
177	
178			// Play/pause state
179			this.audio.addEventListener("play", () => {
180				this.playPauseBtn.innerHTML = "&#10074;&#10074;";
181				if (this.textContainer) this.textContainer.dataset.audioPlaying = "true";
182			});
183	
184			this.audio.addEventListener("pause", () => {
185				this.playPauseBtn.innerHTML = "&#9654;";
186				if (this.textContainer) this.textContainer.dataset.audioPlaying = "false";
187				this.pushEvent("audio_position", {
188					position_ms: Math.round(this.audio.currentTime * 1000),
189				});
190			});
191	
192			// Auto-advance
193			this.audio.addEventListener("ended", () => {
194				const settings = this.loadReaderSettings();
195				if (settings.autoNextChapter) {
196					this.pushEvent("next_chapter", {});
197				}
198			});
199	
200			// Re-sync button
201			if (this.resyncBtn) {
202				this.resyncBtn.addEventListener("click", () => {
203					this.autoScrollPaused = false;
204					this.resyncBtn.classList.add("hidden");
205					// Force scroll to current word
206					if (this.currentWordIndex >= 0 && this.textContainer) {
207						const el = this.textContainer.querySelector(
208							`[data-word-index="${this.currentWordIndex}"]`,
209						);
210						if (el) el.scrollIntoView({ behavior: "smooth", block: "center" });
211					}
212				});
213			}
214	
215			// Manual scroll detection from ScrollTracker
216			this._manualScrollHandler = () => {
217				if (!this.audio.paused && !this.isAutoScrolling) {
218					this.autoScrollPaused = true;
219					if (this.resyncBtn) this.resyncBtn.classList.remove("hidden");
220				}
221			};
222			window.addEventListener("manual-scroll", this._manualScrollHandler);
223	
224			// Auto-scroll lifecycle events
225			this._autoScrollStartHandler = () => {
226				this.isAutoScrolling = true;
227			};
228			this._autoScrollEndHandler = () => {
229				this.isAutoScrolling = false;
230			};
231			window.addEventListener("auto-scroll-start", this._autoScrollStartHandler);
232			window.addEventListener("auto-scroll-end", this._autoScrollEndHandler);
233	
234			// LiveView event handlers
235			this.handleEvent("toggle_audio", () => this.togglePlayback());
236			this.handleEvent("toggle_mute", () => {
237				this.audio.muted = !this.audio.muted;
238			});
239			this.handleEvent("change_speed", ({ direction }) => {
240				const speeds = [0.5, 0.75, 1, 1.25, 1.5, 1.75, 2];
241				const cur = this.audio.playbackRate;
242				const idx = speeds.findIndex((s) => Math.abs(s - cur) < 0.01);
243				let next;
244				if (direction === "up")
245					next = speeds[Math.min(speeds.length - 1, idx + 1)];
246				else next = speeds[Math.max(0, idx - 1)];
247				this.setSpeed(next);
248			});
249			this.handleEvent("toggle_pill", () => {
250				// Delegate to FloatingPillHook via CustomEvent
251				window.dispatchEvent(new CustomEvent("toggle-pill"));
252			});
253	
254			// Set up IntersectionObserver for auto-restore of re-sync state
255			this.setupIntersectionObserver();
256		},
257	
258		setupScrubber(scrubber) {
259			const getPercent = (clientX) => {
260				const rect = scrubber.getBoundingClientRect();
261				if (rect.width === 0) return 0;
262				return Math.min(1, Math.max(0, (clientX - rect.left) / rect.width));
263			};
264	
265			const seek = (clientX) => {
266				if (this.audio.duration && Number.isFinite(this.audio.duration)) {
267					const pct = getPercent(clientX);
268					this.audio.currentTime = pct * this.audio.duration;
269				}
270			};
271	
272			// Click handler (simple single-click seek)
273			scrubber.addEventListener("click", (e) => {
274				seek(e.clientX);
275			});
276	
277			// Mouse drag events
278			let isDragging = false;
279			scrubber.addEventListener("mousedown", (e) => {
280				isDragging = true;
281				seek(e.clientX);
282				e.preventDefault();
283			});
284			const onMouseMove = (e) => {
285				if (isDragging) seek(e.clientX);
286			};
287			const onMouseUp = () => {
288				isDragging = false;
289			};
290			window.addEventListener("mousemove", onMouseMove);
291			window.addEventListener("mouseup", onMouseUp);
292			this._scrubberCleanups.push(() => {
293				window.removeEventListener("mousemove", onMouseMove);
294				window.removeEventListener("mouseup", onMouseUp);
295			});
296	
297			// Touch events
298			scrubber.addEventListener(
299				"touchstart",
300				(e) => {
301					e.preventDefault();
302					seek(e.touches[0].clientX);
303				},
304				{ passive: false },
305			);
306			scrubber.addEventListener(
307				"touchmove",
308				(e) => {
309					e.preventDefault();
310					seek(e.touches[0].clientX);
311				},
312				{ passive: false },
313			);
314			scrubber.addEventListener(
315				"touchend",
316				(e) => {
317					e.preventDefault();
318					if (e.changedTouches[0]) seek(e.changedTouches[0].clientX);
319				},
320				{ passive: false },
321			);
322		},
323	
324		setupWordClickListeners() {
325			if (!this.textContainer) return;
326			this.textContainer.querySelectorAll("[data-word-index]").forEach((el) => {
327				el.addEventListener("click", () => {
328					const idx = parseInt(el.dataset.wordIndex, 10);
329					if (idx >= 0 && idx < this.timings.length) {
330						this.audio.currentTime = this.timings[idx].start_ms / 1000;
331						if (this.audio.paused) this.audio.play();
332					}
333				});
334			});
335		},
336	
337		setupIntersectionObserver() {
338			if (!this.textContainer || !window.IntersectionObserver) return;
339			this._intersectionObserver = new IntersectionObserver(
340				(entries) => {
341					entries.forEach((entry) => {
342						if (entry.isIntersecting && this.autoScrollPaused) {
343							this.autoScrollPaused = false;
344							if (this.resyncBtn) this.resyncBtn.classList.add("hidden");
345						}
346					});
347				},
348				{ threshold: 0.5 },
349			);
350		},
351	
352		togglePlayback() {
353			if (this.audio.paused) {
354				this.audio.play();
355			} else {
356				this.audio.pause();
357			}
358		},
359	
360		setSpeed(speed) {
361			this.audio.playbackRate = speed;
362			localStorage.setItem("readaloud-playback-speed", speed);
363			this.updateSpeedButtons(speed);
364		},
365	
366		updateSpeedButtons(speed) {
367			// Update speed badge display
368			const badge = document.getElementById("speed-badge");
369			if (badge) {
370				badge.textContent = speed === 1 ? "1x" : `${speed}x`;
371			}
372			// Update legacy dropdown buttons if present
373			this.el.querySelectorAll("[data-speed]").forEach((btn) => {
374				const btnSpeed = parseFloat(btn.dataset.speed);
375				btn.classList.toggle("btn-active", Math.abs(btnSpeed - speed) < 0.01);
376			});
377		},
378	
379		highlightWord(ms) {
380			if (!this.textContainer || this.timings.length === 0) return;
381	
382			// Binary search for active word (matches ln-reader approach)
383			let idx = -1;
384			let lo = 0;
385			let hi = this.timings.length - 1;
386	
387			while (lo <= hi) {
388				const mid = (lo + hi) >>> 1;
389				const t = this.timings[mid];
390				if (ms >= t.start_ms && ms < t.end_ms) {
391					idx = mid;
392					break;
393				} else if (ms < t.start_ms) {
394					hi = mid - 1;
395				} else {
396					// ms >= t.end_ms — keep track of the last word we passed
397					idx = mid;
398					lo = mid + 1;
399				}
400			}
401	
402			// If we landed past a word, check if we're actually in the next one
403			if (idx >= 0 && idx < this.timings.length - 1) {
404				const next = this.timings[idx + 1];
405				if (ms >= next.start_ms) {
406					idx = idx + 1;
407				}
408			}
409	
410			if (idx === this.currentWordIndex) return;
411	
412			// Remove old active/spoken classes
413			if (this.currentWordIndex >= 0) {
414				const oldActive = this.textContainer.querySelector(
415					`[data-word-index="${this.currentWordIndex}"]`,
416				);
417				if (oldActive) {
418					oldActive.classList.remove("word-active");
419					oldActive.classList.add("word-spoken");
420				}
421			}
422	
423			// Add new active word
424			if (idx >= 0) {
425				const newActive = this.textContainer.querySelector(
426					`[data-word-index="${idx}"]`,
427				);
428				if (newActive) {
429					newActive.classList.add("word-active");
430					newActive.classList.remove("word-spoken");
431	
432					// Auto-scroll to active word if not paused by user
433					if (!this.autoScrollPaused) {
434						window.dispatchEvent(new CustomEvent("auto-scroll-start"));
435						newActive.scrollIntoView({ behavior: "smooth", block: "center" });
436						// Clear previous timeout to prevent overlap at high playback speeds
437						clearTimeout(this._autoScrollEndTimer);
438						this._autoScrollEndTimer = setTimeout(
439							() => window.dispatchEvent(new CustomEvent("auto-scroll-end")),
440							800,
441						);
442	
443						// IntersectionObserver: watch the active word
444						if (this._intersectionObserver) {
445							this._intersectionObserver.disconnect();
446							this._intersectionObserver.observe(newActive);
447						}
448					}
449				}
450			}
451	
452			// Apply word-spoken to all words before current index
453			// Only update the range that changed to avoid full re-scan
454			if (idx > this.currentWordIndex) {
455				for (let i = Math.max(0, this.currentWordIndex); i < idx; i++) {
456					const el = this.textContainer.querySelector(`[data-word-index="${i}"]`);
457					if (el) {
458						el.classList.remove("word-active");
459						el.classList.add("word-spoken");
460					}
461				}
462			} else if (idx >= 0 && idx < this.currentWordIndex) {
463				// Seeked backwards: remove spoken from words after new index
464				for (let i = idx + 1; i <= this.currentWordIndex; i++) {
465					const el = this.textContainer.querySelector(`[data-word-index="${i}"]`);
466					if (el) {
467						el.classList.remove("word-spoken");
468						el.classList.remove("word-active");
469					}
470				}
471			}
472	
473			this.currentWordIndex = idx;
474		},
475	
476		loadReaderSettings() {
477			try {
478				return JSON.parse(
479					localStorage.getItem("readaloud-reader-settings") || "{}",
480				);
481			} catch {
482				return {};
483			}
484		},
485	
486		formatTime(secs) {
487			const m = Math.floor(secs / 60);
488			const s = Math.floor(secs % 60);
489			return `${m}:${s < 10 ? "0" : ""}${s}`;
490		},
491	
492		destroyed() {
493			if (this._stopHighlightLoop) this._stopHighlightLoop();
494			if (this.audio) this.audio.pause();
495			if (this._manualScrollHandler)
496				window.removeEventListener("manual-scroll", this._manualScrollHandler);
497			if (this._autoScrollStartHandler)
498				window.removeEventListener(
499					"auto-scroll-start",
500					this._autoScrollStartHandler,
501				);
502			if (this._autoScrollEndHandler)
503				window.removeEventListener("auto-scroll-end", this._autoScrollEndHandler);
504			if (this._intersectionObserver) this._intersectionObserver.disconnect();
505			if (this._scrubberCleanups) {
506				for (const fn of this._scrubberCleanups) fn();
507			}
508			clearTimeout(this._autoScrollEndTimer);
509		},
510	};
511

